251→                }
252→            }
253→        }
254→    }
255→}
256→internal val ISO_OFFSET_BASIC by lazy {
257→    UtcOffsetFormat.build {
258→        alternativeParsing({ chars("z") }) {
259→            optional("Z") {
260→                offsetHours()
261→                optional {
262→                    offsetMinutesOfHour()
263→                    optional {
264→                        offsetSecondsOfMinute()
265→                    }
266→                }
267→            }
268→        }
269→    }
270→}
