  6→package kotlinx.datetime.internal.format
  7→
  8→import kotlinx.datetime.internal.format.formatter.*
  9→import kotlinx.datetime.internal.format.parser.*
 10→import kotlinx.datetime.internal.isAsciiDigit
 11→
 12→internal sealed interface FormatStructure<in T> {
 13→    fun parser(): ParserStructure<T>
 14→    fun formatter(): FormatterStructure<T>
 15→}
 16→
 17→internal class BasicFormatStructure<in T>(
 18→    val directive: FieldFormatDirective<T>
 19→) : NonConcatenatedFormatStructure<T> {
 20→    override fun toString(): String = "BasicFormatStructure($directive)"
 21→
 22→    override fun equals(other: Any?): Boolean = other is BasicFormatStructure<*> && directive == other.directive
 23→    override fun hashCode(): Int = directive.hashCode()
 24→
 25→    override fun parser(): ParserStructure<T> = directive.parser()
 26→    override fun formatter(): FormatterStructure<T> = directive.formatter()
 27→}
 28→
 29→internal class ConstantFormatStructure<in T>(
 30→    val string: String
 31→) : NonConcatenatedFormatStructure<T> {
 32→    override fun toString(): String = "ConstantFormatStructure($string)"
 33→
 34→    override fun equals(other: Any?): Boolean = other is ConstantFormatStructure<*> && string == other.string
 35→    override fun hashCode(): Int = string.hashCode()
 36→
 37→    override fun parser(): ParserStructure<T> = ParserStructure(
 38→        operations = when {
 39→            string.isEmpty() -> emptyList()
 40→            else -> buildList {
 41→                val suffix = if (string[0].isAsciiDigit()) {
 42→                    add(NumberSpanParserOperation(listOf(ConstantNumberConsumer(string.takeWhile {
 43→                        it.isAsciiDigit()
 44→                    }))))
 45→                    string.dropWhile { it.isAsciiDigit() }
 46→                } else {
 47→                    string
 48→                }
 49→                if (suffix.isNotEmpty()) {
 50→                    if (suffix[suffix.length - 1].isAsciiDigit()) {
 51→                        add(PlainStringParserOperation(suffix.dropLastWhile { it.isAsciiDigit() }))
 52→                        add(NumberSpanParserOperation(listOf(ConstantNumberConsumer(suffix.takeLastWhile {
 53→                            it.isAsciiDigit()
 54→                        }))))
 55→                    } else {
 56→                        add(PlainStringParserOperation(suffix))
 57→                    }
 58→                }
 59→            }
 60→        },
 61→        followedBy = emptyList()
 62→    )
 63→
 64→    override fun formatter(): FormatterStructure<T> = ConstantStringFormatterStructure(string)
 65→}
 66→
 67→internal class SignedFormatStructure<in T>(
 68→    val format: FormatStructure<T>,
 69→    val withPlusSign: Boolean,
 70→) : NonConcatenatedFormatStructure<T> {
 71→
 72→    private val fieldSigns = basicFormats(format).mapNotNull { it.field.sign }.toSet()
 73→
 74→    init {
 75→        require(fieldSigns.isNotEmpty()) { "Signed format must contain at least one field with a sign" }
 76→    }
 77→
 78→    override fun toString(): String = "SignedFormatStructure($format)"
 79→
 80→    override fun equals(other: Any?): Boolean =
 81→        other is SignedFormatStructure<*> && format == other.format && withPlusSign == other.withPlusSign
 82→
 83→    override fun hashCode(): Int = 31 * format.hashCode() + withPlusSign.hashCode()
 84→
 85→    override fun parser(): ParserStructure<T> = listOf(
 86→        ParserStructure(
 87→            operations = listOf(
 88→                SignParser(
 89→                    isNegativeSetter = { value, isNegative ->
 90→                        for (field in fieldSigns) {
 91→                            val wasNegative = field.isNegative.getter(value) == true
 92→                            // TODO: replacing `!=` with `xor` fails on JS
 93→                            field.isNegative.trySetWithoutReassigning(value, isNegative != wasNegative)
 94→                        }
 95→                    },
 96→                    withPlusSign = withPlusSign,
 97→                    whatThisExpects = "sign for ${this.fieldSigns}"
 98→                )
 99→            ),
100→            emptyList()
101→        ), format.parser()
102→    ).concat()
103→
104→    override fun formatter(): FormatterStructure<T> {
105→        val innerFormat = format.formatter()
106→        fun checkIfAllNegative(value: T): Boolean {
107→            var seenNonZero = false
108→            for (check in fieldSigns) {
109→                when {
110→                    check.isNegative.getter(value) == true -> seenNonZero = true
111→                    check.isZero(value) -> continue
112→                    else -> return false
113→                }
114→            }
115→            return seenNonZero
116→        }
117→        return SignedFormatter(
118→            innerFormat,
119→            ::checkIfAllNegative,
120→            withPlusSign
121→        )
122→    }
123→}
124→
125→internal class AlternativesParsingFormatStructure<in T>(
126→    val mainFormat: FormatStructure<T>,
127→    val formats: List<FormatStructure<T>>,
128→) : NonConcatenatedFormatStructure<T> {
129→    override fun toString(): String = "AlternativesParsing($formats)"
130→
131→    override fun equals(other: Any?): Boolean =
132→        other is AlternativesParsingFormatStructure<*> && mainFormat == other.mainFormat && formats == other.formats
133→
134→    override fun hashCode(): Int = 31 * mainFormat.hashCode() + formats.hashCode()
135→
136→    override fun parser(): ParserStructure<T> = ParserStructure(operations = emptyList(), followedBy = buildList {
137→        add(mainFormat.parser())
138→        for (format in formats) {
139→            add(format.parser())
140→        }
141→    })
142→
143→    override fun formatter(): FormatterStructure<T> = mainFormat.formatter()
144→}
145→
146→internal class OptionalFormatStructure<in T>(
147→    val onZero: String,
148→    val format: FormatStructure<T>,
149→) : NonConcatenatedFormatStructure<T> {
150→    override fun toString(): String = "Optional($onZero, $format)"
151→
152→    private val fields = basicFormats(format).map { it.field }.distinct().map { field ->
153→        PropertyWithDefault.fromField(field)
154→    }
155→
156→    override fun equals(other: Any?): Boolean =
157→        other is OptionalFormatStructure<*> && onZero == other.onZero && format == other.format
158→
159→    override fun hashCode(): Int = 31 * onZero.hashCode() + format.hashCode()
160→
161→    override fun parser(): ParserStructure<T> = ParserStructure(
162→        operations = emptyList(),
163→        followedBy = listOf(
164→            format.parser(),
165→            listOf(
166→                ConstantFormatStructure<T>(onZero).parser(),
167→                ParserStructure(
168→                    if (fields.isEmpty()) {
169→                        emptyList()
170→                    } else {
171→                        listOf(
172→                            UnconditionalModification {
173→                                for (field in fields) {
174→                                    field.assignDefault(it)
175→                                }
176→                            }
177→                        )
178→                    },
179→                    emptyList()
180→                )
181→            ).concat()
182→        )
183→    )
184→
185→    override fun formatter(): FormatterStructure<T> {
186→        val formatter = format.formatter()
187→        val predicate = conjunctionPredicate(fields.map { it.isDefaultComparisonPredicate() })
188→        return if (predicate is Truth) {
189→            ConstantStringFormatterStructure(onZero)
190→        } else {
191→            ConditionalFormatter(
192→                listOf(
193→                    predicate::test to ConstantStringFormatterStructure(onZero),
194→                    Truth::test to formatter
195→                )
196→            )
197→        }
198→    }
199→
200→    private class PropertyWithDefault<in T, E> private constructor(
201→        private val accessor: Accessor<T, E>,
202→        private val defaultValue: E
203→    ) {
204→        companion object {
205→            fun <T, E> fromField(field: FieldSpec<T, E>): PropertyWithDefault<T, E> {
206→                val default = field.defaultValue
207→                require(default != null) {
208→                    "The field '${field.name}' does not define a default value"
209→                }
210→                return PropertyWithDefault(field.accessor, default)
211→            }
212→        }
213→
214→        inline fun assignDefault(target: T) {
215→            accessor.trySetWithoutReassigning(target, defaultValue)
216→        }
217→
218→        inline fun isDefaultComparisonPredicate() = ComparisonPredicate(defaultValue, accessor::getter)
219→    }
220→}
221→
222→internal sealed interface NonConcatenatedFormatStructure<in T> : FormatStructure<T>
223→
224→internal open class ConcatenatedFormatStructure<in T>(
225→    val formats: List<NonConcatenatedFormatStructure<T>>
226→) : FormatStructure<T> {
227→    override fun toString(): String = "ConcatenatedFormatStructure(${formats.joinToString(", ")})"
228→
229→    override fun equals(other: Any?): Boolean = other is ConcatenatedFormatStructure<*> && formats == other.formats
230→
231→    override fun hashCode(): Int = formats.hashCode()
232→
233→    override fun parser(): ParserStructure<T> = formats.map { it.parser() }.concat()
234→
235→    override fun formatter(): FormatterStructure<T> {
236→        val formatters = formats.map { it.formatter() }
237→        return if (formatters.size == 1) {
238→            formatters.single()
239→        } else {
240→            ConcatenatedFormatter(formatters)
241→        }
242→    }
243→}
244→
245→internal class CachedFormatStructure<in T>(formats: List<NonConcatenatedFormatStructure<T>>) :
246→    ConcatenatedFormatStructure<T>(formats) {
247→    private val cachedFormatter: FormatterStructure<T> = super.formatter()
248→    private val cachedParser: ParserStructure<T> = super.parser()
249→
250→    override fun formatter(): FormatterStructure<T> = cachedFormatter
251→
252→    override fun parser(): ParserStructure<T> = cachedParser
253→}
254→
255→private fun <T> basicFormats(format: FormatStructure<T>): List<FieldFormatDirective<T>> = buildList {
256→    fun rec(format: FormatStructure<T>) {
257→        when (format) {
258→            is BasicFormatStructure -> add(format.directive)
259→            is ConcatenatedFormatStructure -> format.formats.forEach { rec(it) }
260→            is ConstantFormatStructure -> {}
261→            is SignedFormatStructure -> rec(format.format)
262→            is AlternativesParsingFormatStructure -> {
263→                rec(format.mainFormat); format.formats.forEach { rec(it) }
264→            }
265→
266→            is OptionalFormatStructure -> rec(format.format)
267→        }
268→    }
269→    rec(format)
270→}
