 29→internal class ConstantFormatStructure<in T>(
 30→    val string: String
 31→) : NonConcatenatedFormatStructure<T> {
 32→    override fun toString(): String = "ConstantFormatStructure($string)"
 33→
 34→    override fun equals(other: Any?): Boolean = other is ConstantFormatStructure<*> && string == other.string
 35→    override fun hashCode(): Int = string.hashCode()
 36→
 37→    override fun parser(): ParserStructure<T> = ParserStructure(
 38→        operations = when {
 39→            string.isEmpty() -> emptyList()
 40→            else -> buildList {
 41→                val suffix = if (string[0].isAsciiDigit()) {
 42→                    add(NumberSpanParserOperation(listOf(ConstantNumberConsumer(string.takeWhile {
 43→                        it.isAsciiDigit()
 44→                    }))))
 45→                    string.dropWhile { it.isAsciiDigit() }
 46→                } else {
 47→                    string
 48→                }
 49→                if (suffix.isNotEmpty()) {
 50→                    if (suffix[suffix.length - 1].isAsciiDigit()) {
 51→                        add(PlainStringParserOperation(suffix.dropLastWhile { it.isAsciiDigit() }))
 52→                        add(NumberSpanParserOperation(listOf(ConstantNumberConsumer(suffix.takeLastWhile {
 53→                            it.isAsciiDigit()
 54→                        }))))
 55→                    } else {
 56→                        add(PlainStringParserOperation(suffix))
 57→                    }
 58→                }
 59→            }
 60→        },
 61→        followedBy = emptyList()
 62→    )
 63→
 64→    override fun formatter(): FormatterStructure<T> = ConstantStringFormatterStructure(string)
 65→}
