    val secondsOfMinute = object : UnsignedFieldSpec(
        accessor = PropertyAccessor(UtcOffsetFieldContainer::secondsOfMinute),
        defaultValue = 0,
        minValue = 0,
        maxValue = 59,
        sign = sign,
    ) {
        override val displayName: String get() = "offsetSecondsOfMinute"
    }
