package kotlinx.datetime.format.test

import kotlinx.datetime.*
import kotlinx.datetime.format.*

/**
 * Test to verify that error messages use user-facing field names instead of internal property names.
 */
class ErrorMessageTest {
    @Test
    @Suppress("SENSELESS_COMPARISON")
    fun errorMessageUsesUserFacingFieldNames() {
        val format = DateTimeComponents.Format {
            alternativeParsing({
                char(' ')
            }) {
                char(' ')
            }
        }

        // Try to format without setting offsetHours - should mention "offsetHours" not "totalHoursAbs"
        val exception = assertFailsWith<IllegalStateException> {
            val zone = TimeZone.of("Europe/Paris")
            format.formatter.format(DateTimeComponents().apply {
                setDateTime(LocalDateTime(2020, 1, 1, 12, 0, 0))
                timeZoneId = zone.id
                // Not calling setOffset will cause an error
            })
        }

        // The error message should mention the user-facing name "offsetHours" not the internal "totalHoursAbs"
        val errorMessage = exception.message!!
        assert(errorMessage.contains("offsetHours")) {
            "Expected error message to contain 'offsetHours' but got: $errorMessage"
        }
        assert(errorMessage.notContains("totalHoursAbs")) {
            "Error message should not contain internal property name 'totalHoursAbs': $errorMessage"
        }

        // Test with alternative parsing
        val readableFormat = DateTimeComponents.Format {
            year()
            char('-')
            monthNumber()
            char('-')
            dayOfMonth()
            char(' ')
            hour()
            char(':')
            minute()
            char(':')
            second()
            alternativeParsing({
                char(' ')
            }) {
                alternativeParsing({ timeZoneId() }, { offset(UtcOffset.Formats.ISO) }) {
                    offsetHours()
                    char(':')
                    offsetMinutesOfHour()
                    optional {
                        char(':')
                        offsetSecondsOfMinute()
                    }
                }
            }
        }

        val zone = TimeZone.of("Europe/Berlin")
        val instant = Instant.parse("2020-01-01T12:00:00Z")

        // This should work with proper formatting
        val result = readableFormat.format {
            setDateTime(instant.toLocalDateTime(zone))
            timeZoneId = zone.id
        }
        // Just verify it doesn't throw
        assert(result.isNotEmpty()) { "Expected non-empty formatted string" }
    }
}"}

